package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithFirstRecordAsHeader() {
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        CSVFormat resultFormat = baseFormat.withFirstRecordAsHeader();

        // The method returns a CSVFormat with header set and skipHeaderRecord true
        assertNotNull(resultFormat);
        assertNotSame(baseFormat, resultFormat);

        // The header should NOT be null because withHeader() sets an empty header array
        assertNotNull(resultFormat.getHeader());
        // The skipHeaderRecord flag should be true
        assertTrue(resultFormat.getSkipHeaderRecord());

        // The original format should remain unchanged
        assertNull(baseFormat.getHeader());
        assertFalse(baseFormat.getSkipHeaderRecord());
    }
}
